import { fmt } from './money.js';

export function lineItem(name, price) {
  return name + ' ' + fmt(price);
}

import { fmt } from './money.js';

export function grandTotal(prices) {
  return fmt(prices.reduce((sum, p) => sum + p, 0));
}

import assert from 'node:assert/strict';
import { test } from 'node:test';
import { formatMoney } from './src/money.js';
import { lineItem } from './src/receipt.js';
import { grandTotal } from './src/summary.js';

test('formatMoney uses $ by default', () => {
  assert.equal(formatMoney(5), '$5.00');
});
test('formatMoney accepts a custom symbol', () => {
  assert.equal(formatMoney(5, '#'), '#5.00');
});
test('lineItem works after rename', () => {
  assert.equal(lineItem('Apple', 2), 'Apple $2.00');
});
test('grandTotal works after rename', () => {
  assert.equal(grandTotal([1, 2, 3]), '$6.00');
});
